#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int rd(char *s)
{
	int p=0;char ch;while(ch<'a'||ch>'z')ch=getchar();
	while(ch<='z'&&ch>='a')s[++p]=ch,ch=getchar();return p;
}
inline int min(int x,int y){return x<y?x:y;}
const int N=5e5+10,base=31,Mod=1e9+7;
char s[N];int mxl[N],hsh[N],inv[N];int n;
inline bool qry(int l1,int r1,int l2,int r2)
{
	int q1=1ll*(hsh[r1]-hsh[l1-1]+Mod)*inv[l2-l1]%Mod,q2=(hsh[r2]-hsh[l2-1]);
	return q1==(q2<0?q2+Mod:q2);
}
inline int fnd(int k)
{
	if(s[k]!=s[1])return 0;if(k==n)return 1;int l=1,r=n-k+1,res=1,mid;
	while(l<=r)(mid=(l+r)>>1,qry(1,mid,k,k+mid-1))?(l=mid+1,res=mid):(r=mid-1);return res;
}
int main()
{
	n=rd(s);inv[0]=1;rep(1,n,i)inv[i]=1ll*inv[i-1]*base%Mod;
	rep(1,n,i)hsh[i]=hsh[i-1]+1ll*inv[i-1]*(s[i]-'a')%Mod,hsh[i]>Mod?hsh[i]-=Mod:0;
	rep(1,n,i)mxl[i]=fnd(i); int ans=0x3f3f3f3f;
	rep(1,n,i)if(i+mxl[i]-1==n)
	{
		int pre=1;bool flag=0;rep(1,n,j)
		{
			if(j-pre>mxl[i]){flag=1;break;}
			if(mxl[j]>=mxl[i])pre=j;
		}
		if(!flag){ans=min(ans,mxl[i]);}
	}
	printf("%d\n",ans);return 0;
}
